(function(){"use strict";var VOTES_KEY="wgp_hotnot_votes_v1";var ADOPTED_KEY="wgp_hotnot_verdict_v1";var FAV_KEY="wg_favourites";var HOT_KEY="wg_hotpicks";var RECENT_KEY="wg_recent";var WEIGHT={hot:5,fav:4,vote_hot:3,recent:2,quiz:2};function inferGenre(game){var n=(game&&(game.name||game.title)||"").toLowerCase();if(/mahjong/.test(n))return"Mahjong";if(/solitaire|hex|match|merge|2048|cubica|tile/.test(n))return"Puzzle";if(/puzzle|sort|block|jam|hexa|polygon|pins|pop/.test(n))return"Puzzle";if(/shoot|sniper|cs:|fps|brigade|delta|battle shot|raid|warfare|commando|mech/.test(n))return"Shooter";if(/zombie|war|fight|brawl|combat|army|fps/.test(n))return"Action";if(/race|drift|drive|traffic|parking|car|tank|highway|truck|bus mania|sling/.test(n))return"Racing";if(/golf|football|tennis|sport|billiards|fishing|ping pong/.test(n))return"Sport";if(/garden|farm|merge|idle|empire|mining|coin|sort/.test(n))return"Casual";if(/quest|kingdom|hero|magic|spell|adventure|journey|forest/.test(n))return"RPG";if(/tower|defense|guardian|defend/.test(n))return"Tower Defense";if(/cryptogram|hangman|spell|words|mind|cross|chess/.test(n))return"Puzzle";if(/cards|solitaire|poker/.test(n))return"Cards";return"Arcade"}function readList(key){try{var raw=localStorage.getItem(key);if(!raw)return[];var a=JSON.parse(raw);return Array.isArray(a)?a:[]}catch(e){return[]}}function readVerdictRecord(key){try{var raw=localStorage.getItem(key);return raw?JSON.parse(raw):null}catch(e){return null}}function readQuizGenres(){var v=readVerdictRecord(ADOPTED_KEY);if(!v)return{genres:[],persona:null};if(v.adopted||v.isAdopted){return{genres:[],persona:null}}var g=[];if(v.topGenre)g.push(v.topGenre);if(Array.isArray(v.allGenres)){v.allGenres.forEach(function(x){if(g.indexOf(x)===-1)g.push(x)})}return{genres:g,persona:v.title?{title:v.title,emoji:v.emoji||"\u2728",sub:v.sub||""}:null}}function deriveArchetype(stats){var total=stats.totalActs;var distinct=stats.distinctGenres;var top=stats.topShare;if(total<3)return{key:"newcomer",title:"Newcomer",emoji:"\u{1F331}",sub:"Taste still forming"};if(stats.hotCount+stats.favCount>=14)return{key:"collector",title:"Collector",emoji:"\u{1F4DA}",sub:"Plays it all, keeps a lot"};if(distinct>=5&&top<.45)return{key:"explorer",title:"Explorer",emoji:"\u{1F9ED}",sub:"Roams across genres"};if(top>=.55||distinct<=2)return{key:"strategist",title:"Strategist",emoji:"\u265F\uFE0F",sub:"Goes deep in a lane"};if(stats.lovedCount>=1&&total<=6)return{key:"curator",title:"Curator",emoji:"\u{1F3AF}",sub:"Picky, keeps only the best"};return{key:"enthusiast",title:"Enthusiast",emoji:"\u2728",sub:"A bit of everything they love"}}function confidenceFrom(weightedTotal,distinctGenres){return Math.min(100,Math.round(Math.min(70,weightedTotal*3.2)+Math.min(30,distinctGenres*6)))}function compute(){var hots=readList(HOT_KEY);var favs=readList(FAV_KEY);var votes=readList(VOTES_KEY).filter(function(v){return v&&v.choice==="hot"});var recent=readList(RECENT_KEY);var quiz=readQuizGenres();if(!hots.length){votes=[];quiz={genres:[],persona:null}}var scores={};var hotCount=0,favCount=0,lovedCount=0;function bump(rec,weight,isHot,isFav){var g=rec&&rec.genre||inferGenre(rec);if(!g)return;var k=g.toLowerCase();if(!scores[k])scores[k]={label:g,score:0};scores[k].score+=weight;if(isHot)hotCount++;if(isFav)favCount++}hots.forEach(function(r){bump(r,WEIGHT.hot,true,false)});favs.forEach(function(r){bump(r,WEIGHT.fav,false,true);if(typeof r.rating==="number"&&r.rating>=4.5)lovedCount++});votes.forEach(function(r){bump(r,WEIGHT.vote_hot,false,false)});recent.forEach(function(r){bump(r,WEIGHT.recent,false,false)});quiz.genres.forEach(function(g,i){var k=(g||"").toLowerCase();if(!k)return;if(!scores[k])scores[k]={label:g,score:0};scores[k].score+=WEIGHT.quiz*(quiz.genres.length-i)/quiz.genres.length});var ranked=Object.keys(scores).map(function(k){return scores[k]}).sort(function(a,b){return b.score-a.score});var weightedTotal=ranked.reduce(function(s,x){return s+x.score},0);var signature=ranked.slice(0,6).map(function(x){return{genre:x.label,score:x.score,share:weightedTotal?x.score/weightedTotal:0,pct:weightedTotal?Math.round(x.score/weightedTotal*100):0}});var distinctGenres=ranked.length;var topShare=signature.length?signature[0].share:0;var totalActs=hots.length+favs.length+votes.length+recent.length;var archetype=deriveArchetype({totalActs,distinctGenres,topShare,hotCount,favCount,lovedCount});var confidence=confidenceFrom(weightedTotal,distinctGenres);var behavioralActs=hots.length+favs.length+recent.length+votes.length;var hasQuiz=!!quiz.persona;var mature=behavioralActs>=3||hasQuiz;return{signature,topGenres:signature.slice(0,3).map(function(s){return s.genre}),archetype,persona:quiz.persona,confidence,counts:{hot:hots.length,fav:favs.length,vote:votes.length,recent:recent.length,total:totalActs},behavioralActs,hasQuiz,mature,isEmpty:signature.length===0}}function getSignature(){var adopted=readVerdictRecord(ADOPTED_KEY);if(adopted&&(adopted.adopted||adopted.isAdopted)&&Array.isArray(adopted.signature)&&adopted.signature.length){return adopted.signature.slice()}return compute().signature}function getStrength(){var adopted=readVerdictRecord(ADOPTED_KEY);if(adopted&&(adopted.adopted||adopted.isAdopted)&&typeof adopted.strength==="number"){return adopted.strength}return compute().confidence}function getTopGenres(n){n=n||3;return getSignature().slice(0,n).map(function(s){return s.genre})}function strengthLabel(s){if(s>=70)return"Strong taste";if(s>=35)return"Forming taste";if(s>0)return"Getting started";return"No votes yet"}function encodeSignature(sig){sig=sig||getSignature();return sig.map(function(s){return s.genre.toLowerCase().replace(/[^a-z0-9]+/g,"-")+"~"+(s.pct||Math.round((s.share||0)*100))}).join("|")}window.wgpTasteProfile={inferGenre,compute,getSignature,getStrength,getTopGenres,strengthLabel,encodeSignature,_readVotes:function(){return readList(VOTES_KEY)},_readFavs:function(){return readList(FAV_KEY)},_readHots:function(){return readList(HOT_KEY)},_readRecent:function(){return readList(RECENT_KEY)}}})();
